#include<iostream>
#include<string>
using namespace std;
int maxVowels(string s, int k) {
        int max=-1;
        for(int i=0;i<=s.length()-k;i++){
            int ans=0;
            for(int j=i;j<i+k;j++){
               if(s[j]=='a' || s[j]=='e' || s[j]== 'i'||s[j]=='o'||s[j]=='u'){
                ans=ans+1;
               }
            }
            if(ans>max){
                max=ans;
            }
        }
        return max;
}

int main(){
    string s="";
    cout<<maxVowels(s,50436);

}

